// ─── Types ───────────────────────────────────────────────────────────────────

type ContractType = 'mentoria' | 'compravenda' | 'embaixadores' | 'imagem';

interface Contratante {
  id: string;
  nome: string;
  nacionalidade: string;
  estadoCivil: string;
  profissao: string;
  cpf: string;
  rua: string;
  numero: string;
  bairro: string;
  cidade: string;
  estado: string;
  cep: string;
  email: string;
  telefone: string;
}

interface ContractData {
  contractType: ContractType;
  numeroContrato: string;
  contratantes: Contratante[];
  valorTotal: number;
  valorEntrada: number;
  numParcelas: number;
  duracaoMentoria: number;
  duracaoAulas: number;
  dataContrato: string;
  formaPagamentoSaldo: string;
  dataPrimeiraParcela: string;
  formaPagamentoEntrada: string;
  marcas: string[];
  selectedBonuses: number[];
  bonusDurations: { [key: number]: number };
  // Compra e Venda fields
  produtoMarca: string;
  produtoModelo: string;
  produtoArmazenamento: string;
  produtoNumSerie: string;
  produtoAcessorios: string;
  diaVencimento: string;
  // Embaixadores fields
  instagramEmbaixador: string;
  instagramLoja: string;
  pubsFeed: string;
  pubsStories: string;
  produtoEmbaixador: string;
}

